+	display: inline-block;
+	width: 50px;
+	height: 50px;
+	margin: 5px;
+	border-radius: 15px;
+
+	background-color: rgba(124, 124, 124, 0.3);
+
+	transition: linear  0.2s;
+}
+
+.icon:hover {
+	background-color: rgba(185, 185, 185, 0.3);
+	transform: scale(1.05);
+}
