+	padding: 5px;
+	
+	background-color: rgba(0, 0, 0, 0.7);
+
+	height: 70px;
+	width: 100%;
+
+	overflow-x: scroll;
+	overflow-y: hidden;
+	scrollbar-color: #424242 #999999;
+	scrollbar-width: thin;
